import React from 'react';
import { useParams } from 'react-router-dom';

function ListingDetail() {
  const { id } = useParams();

  return (
    <div className="listing-detail">
      <h1>Объявление #{id}</h1>
      <p>Детальная информация об объявлении</p>
    </div>
  );
}

export default ListingDetail;
